export default {
	data() {
		return {
			qrCode: '/static/images/xcx.jpg'
		};
	},
	methods: {
		order() {
			uni.navigateTo({
				url: '/pages/order/order'
			});
		},
		showImg(){
			let imgs = []
			imgs.push(this.qrCode);
			uni.previewImage({
				current: 0,
				urls: imgs
			});
		}
	}
};
